mapper.select:
SELECT users.id as id, users.cover as cover, users.name as name, users.email as email, users.create_time as create_time, users.update_time as update_time, users.data_scope as data_scope, users.brand_id as brand_id, (SELECT string_agg(uc.cinema_id::text, ',' ORDER BY uc.cinema_id) FROM user_cinema uc WHERE uc.user_id = users.id) AS cinema_ids_csv, (SELECT json_agg(coalesce(c.name, '#' || uc.cinema_id::text) ORDER BY uc.cinema_id) FROM user_cinema uc LEFT JOIN cinema c ON c.id = uc.cinema_id WHERE uc.user_id = users.id) AS cinema_names_json, role.id as role_id, role.name as role_name FROM users LEFT JOIN user_role ON user_role.user_id = users.id LEFT JOIN role ON user_role.role_id = role.id
users.deleted = 0
AND users.id = #{query.id}
AND users.name LIKE concat('%', #{query.name}, '%')
AND users.email = #{query.email}
ORDER BY users.update_time DESC
